package com.vidaysalud.veterinaria.recetaservicio.service;import com.vidaysalud.veterinaria.recetaservicio.client.*;import com.vidaysalud.veterinaria.recetaservicio.dto.*;import com.vidaysalud.veterinaria.recetaservicio.exception.*;import com.vidaysalud.veterinaria.recetaservicio.model.*;import com.vidaysalud.veterinaria.recetaservicio.repository.RecetaRepository;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;@Service @RequiredArgsConstructor @Transactional public class RecetaService{private final RecetaRepository r;private final ConsultaClient consulta;private final MedicamentoClient medicamento;@Transactional(readOnly=true)public List<RecetaResponseDTO>listar(){return r.findAll().stream().map(x->dto(r.findConDetallesByIdReceta(x.getIdReceta()).orElse(x))).toList();}@Transactional(readOnly=true)public RecetaResponseDTO buscar(Integer id){return dto(r.findConDetallesByIdReceta(id).orElseThrow(()->new RecursoNoEncontradoException("Receta no encontrada: "+id)));}public RecetaResponseDTO crear(RecetaRequestDTO d){validar(d);Receta x=map(new Receta(),d);return dto(r.save(x));}public RecetaResponseDTO actualizar(Integer id,RecetaRequestDTO d){validar(d);Receta x=r.findConDetallesByIdReceta(id).orElseThrow(()->new RecursoNoEncontradoException("Receta no encontrada: "+id));x.getDetalles().clear();x.setIdConsulta(d.getIdConsulta());x.setIndicacionesGenerales(d.getIndicacionesGenerales());d.getDetalles().forEach(z->x.agregarDetalle(det(z)));return dto(r.save(x));}public void eliminar(Integer id){r.delete(r.findById(id).orElseThrow(()->new RecursoNoEncontradoException("Receta no encontrada: "+id)));}private void validar(RecetaRequestDTO d){consulta.validar(d.getIdConsulta());Set<Integer>ids=new HashSet<>();for(DetalleRecetaRequestDTO z:d.getDetalles()){medicamento.validar(z.getIdMedicamento());if(!ids.add(z.getIdMedicamento()))throw new DatoDuplicadoException("Medicamento repetido en la receta");}}private Receta map(Receta x,RecetaRequestDTO d){x.setIdConsulta(d.getIdConsulta());x.setIndicacionesGenerales(d.getIndicacionesGenerales());d.getDetalles().forEach(z->x.agregarDetalle(det(z)));return x;}private DetalleReceta det(DetalleRecetaRequestDTO z){return DetalleReceta.builder().idMedicamento(z.getIdMedicamento()).dosis(z.getDosis()).frecuencia(z.getFrecuencia()).duracion(z.getDuracion()).indicaciones(z.getIndicaciones()).build();}private RecetaResponseDTO dto(Receta x){List<DetalleRecetaResponseDTO>ds=x.getDetalles().stream().map(z->DetalleRecetaResponseDTO.builder().idDetalle(z.getIdDetalle()).idMedicamento(z.getIdMedicamento()).dosis(z.getDosis()).frecuencia(z.getFrecuencia()).duracion(z.getDuracion()).indicaciones(z.getIndicaciones()).build()).toList();return RecetaResponseDTO.builder().idReceta(x.getIdReceta()).idConsulta(x.getIdConsulta()).fechaEmision(x.getFechaEmision()).indicacionesGenerales(x.getIndicacionesGenerales()).detalles(ds).build();}}